790: void ConnectionManagerImpl::onDrainTimeout() {
791:   ASSERT(drain_state_ != DrainState::NotDraining);
792:   codec_->goAway();
793:   drain_state_ = DrainState::Closing;
794:   checkForDeferredClose(false);
795: }
