826: void ConnectionManagerImpl::chargeTracingStats(const Tracing::Reason& tracing_reason,
827:                                                ConnectionManagerTracingStats& tracing_stats) {
828:   switch (tracing_reason) {
829:   case Tracing::Reason::ClientForced:
830:     tracing_stats.client_enabled_.inc();
831:     break;
832:   case Tracing::Reason::Sampling:
833:     tracing_stats.random_sampling_.inc();
834:     break;
835:   case Tracing::Reason::ServiceForced:
836:     tracing_stats.service_forced_.inc();
837:     break;
838:   default:
839:     tracing_stats.not_traceable_.inc();
840:     break;
841:   }
842: }
