215: bool ActiveStreamFilterBase::commonHandleAfterDataCallback(FilterDataStatus status,
216:                                                            Buffer::Instance& provided_data,
217:                                                            bool& buffer_was_streaming) {
218: 
219:   if (status == FilterDataStatus::Continue) {
220:     if (iteration_state_ == IterationState::StopSingleIteration) {
221:       commonHandleBufferData(provided_data);
222:       commonContinue();
223:       return false;
224:     } else {
225:       ASSERT(headers_continued_);
226:     }
227:   } else {
228:     iteration_state_ = IterationState::StopSingleIteration;
229:     if (status == FilterDataStatus::StopIterationAndBuffer ||
230:         status == FilterDataStatus::StopIterationAndWatermark) {
231:       buffer_was_streaming = status == FilterDataStatus::StopIterationAndWatermark;
232:       commonHandleBufferData(provided_data);
233:     } else if (observedEndStream() && !hasTrailers() && !bufferedData() &&
234:                // If the stream is destroyed, no need to handle the data buffer or trailers.
235:                // This can occur if the filter calls sendLocalReply.
236:                !parent_.state_.destroyed_) {
237:       // If this filter is doing StopIterationNoBuffer and this stream is terminated with a zero
238:       // byte data frame, we need to create an empty buffer to make sure that when commonContinue
239:       // is called, the pipeline resumes with an empty data frame with end_stream = true
240:       ASSERT(end_stream_);
241:       bufferedData() = createBuffer();
242:     }
243: 
244:     return false;
245:   }
246: 
247:   return true;
248: }
