378: bool ActiveStreamDecoderFilter::canContinue() {
379:   // It is possible for the connection manager to respond directly to a request even while
380:   // a filter is trying to continue. If a response has already happened, we should not
381:   // continue to further filters. A concrete example of this is a filter buffering data, the
382:   // last data frame comes in and the filter continues, but the final buffering takes the stream
383:   // over the high watermark such that a 413 is returned.
384:   return !parent_.stopDecoderFilterChain();
385: }
