387: bool ActiveStreamEncoderFilter::canContinue() {
388:   // As with ActiveStreamDecoderFilter::canContinue() make sure we do not
389:   // continue if a local reply has been sent or ActiveStreamDecoderFilter::recreateStream() is
390:   // called, etc.
391:   return !parent_.state_.encoder_filter_chain_complete_ && !parent_.stopEncoderFilterChain();
392: }
