512: void ActiveStreamDecoderFilter::stopDecodingIfNonTerminalFilterEncodedEndStream(
513:     bool encoded_end_stream) {
514:   // Encoding end_stream by a non-terminal filters (i.e. cache filter) always causes the decoding to
515:   // be stopped even if independent half-close is enabled. For simplicity, independent half-close is
516:   // allowed only when the terminal (router) filter is encoding the response.
517:   if (encoded_end_stream && !parent_.isTerminalDecoderFilter(*this) &&
518:       !parent_.state_.decoder_filter_chain_complete_) {
519:     parent_.state_.decoder_filter_chain_aborted_ = true;
520:   }
