148: bool ActiveStreamFilterBase::commonHandleAfter1xxHeadersCallback(Filter1xxHeadersStatus status) {
149:   ASSERT(parent_.state_.has_1xx_headers_);
150:   ASSERT(!continued_1xx_headers_);
151:   ASSERT(canIterate());
152: 
153:   switch (status) {
154:   case Filter1xxHeadersStatus::Continue:
155:     continued_1xx_headers_ = true;
156:     return true;
157:   case Filter1xxHeadersStatus::StopIteration:
158:     iteration_state_ = IterationState::StopSingleIteration;
159:     return false;
160:   }
161: 
162:   PANIC_DUE_TO_CORRUPT_ENUM;
163: }
