234: void HeaderMapImpl::insertByKey(HeaderString&& key, HeaderString&& value) {
235:   auto lookup = staticLookup(key.getStringView());
236:   if (lookup.has_value()) {
237:     key.clear();
238:     if (*lookup.value().entry_ == nullptr) {
239:       maybeCreateInline(lookup.value().entry_, *lookup.value().key_, std::move(value));
240:     } else {
241:       const auto delimiter = delimiterByHeader(*lookup.value().key_);
242:       const uint64_t added_size =
243:           appendToHeader((*lookup.value().entry_)->value(), value.getStringView(), delimiter);
244:       addSize(added_size);
245:       value.clear();
246:     }
247:   } else {
248:     addSize(key.size() + value.size());
249:     HeaderNode i = headers_.insert(std::move(key), std::move(value));
250:     i->entry_ = i;
251:   }
252: }
