347: HeaderMap::NonConstGetResult HeaderMapImpl::getExisting(absl::string_view key) {
348:   // Attempt a trie lookup first to see if the user is requesting an O(1) header. This may be
349:   // relatively common in certain header matching / routing patterns.
350:   // TODO(mattklein123): Add inline handle support directly to the header matcher code to support
351:   // this use case more directly.
352:   HeaderMap::NonConstGetResult ret;
353:   auto lookup = staticLookup(key);
354:   if (lookup.has_value()) {
355:     if (*lookup.value().entry_ != nullptr) {
356:       ret.push_back(*lookup.value().entry_);
357:     }
358:     return ret;
359:   }
360: 
361:   // If the requested header is not an O(1) header try using the lazy map to
362:   // search for it instead of iterating the headers list.
363:   if (headers_.maybeMakeMap()) {
364:     HeaderList::HeaderLazyMap::iterator iter = headers_.mapFind(key);
365:     if (iter != headers_.mapEnd()) {
366:       const HeaderList::HeaderNodeVector& v = iter->second;
367:       ASSERT(!v.empty()); // It's impossible to have a map entry with an empty vector as its value.
368:       for (const auto& values_it : v) {
369:         // Convert the iterated value to a HeaderEntry*.
370:         ret.push_back(&(*values_it));
371:       }
372:     }
373:     return ret;
374:   }
375: 
376:   // If the requested header is not an O(1) header and the lazy map is not in use, we do a full
377:   // scan. Doing the trie lookup is wasteful in the miss case, but is present for code consistency
378:   // with other functions that do similar things.
379:   for (HeaderEntryImpl& header : headers_) {
380:     if (header.key() == key) {
381:       ret.push_back(&header);
382:     }
383:   }
384: 
385:   return ret;
386: }
