410: size_t HeaderMapImpl::removeIf(const HeaderMap::HeaderMatchPredicate& predicate) {
411:   const size_t old_size = headers_.size();
412:   headers_.removeIf([&predicate, this](const HeaderEntryImpl& entry) {
413:     const bool to_remove = predicate(entry);
414:     if (to_remove) {
415:       // If this header should be removed, make sure any references in the
416:       // static lookup table are cleared as well.
417:       auto lookup = staticLookup(entry.key().getStringView());
418:       if (lookup.has_value()) {
419:         if (lookup.value().entry_) {
420:           const uint32_t key_value_size =
421:               (*lookup.value().entry_)->key().size() + (*lookup.value().entry_)->value().size();
422:           subtractSize(key_value_size);
423:           *lookup.value().entry_ = nullptr;
424:         }
425:       } else {
426:         subtractSize(entry.key().size() + entry.value().size());
427:       }
428:     }
429:     return to_remove;
430:   });
431:   return old_size - headers_.size();
432: }
