496:   const uint64_t size_to_subtract = entry->entry_->key().size() + entry->entry_->value().size();
497:   subtractSize(size_to_subtract);
498:   *ptr_to_entry = nullptr;
499:   headers_.erase(entry->entry_, true);
500:   return 1;
